"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["552"],{70383(e,a,o){o.r(a),o.d(a,{default:()=>s});var n=o(74848),r=o(47643),t=JSON.parse('{"id":219,"es":{"title":"Juego de aventuras de texto mejorado","prompt":"I want you to play a text-based adventure game. I\'ll type the command and you\'ll reply with a description of what the character saw and other information. I hope you only reply the game output and nothing else. Don\'t write explanations. Do not type commands unless I instruct you to do so. When I need supplementary settings, I put the text in brackets (like this). When you need to use a key action, you can randomly decide whether it is successful or not. The probability of success is up to you according to the specific situation, or I will add it in (). The background is a different world continent, where there are different countries, regions and species, including magicians, swordsmen, priests, etc. Please conceive the complete power and key figures. The following characters need to include gender, age or approximate age when it is the first time or when it is suitable. My gender is male and I am 18 years old. Tell me the gender and age of other characters. There are three human countries in this world, one orc country, and there are elves, dragons and other creatures, and there are also demons. Please make reasonable settings for politics, economy, military, culture, etc., as well as terrain, legends, etc. Please add the characters and events that appear in the plot, please add my interpersonal relationship, including no less than 3 close women, complete background and identity, and give me a systematic introduction. Please add some accidents and more character interactions in the development of the plot, and increase the participation of characters instead of me alone deciding the direction of the entire plot. Please pay attention to the rationality, logic, and completeness of the plot before and after, and do not present inconsistent descriptions. Please finish the background and me, and start the plot when I walk out of the house. Respond in Spanish.","description":"Quiero que juegues a un juego de aventuras basado en texto. Yo tecleo las \xf3rdenes y t\xfa respondes con lo que ve el personaje y otra informaci\xf3n. Quiero que respondas s\xf3lo a la salida del juego en chino y nada m\xe1s. No escribas explicaciones. No escribas \xf3rdenes a menos que yo te lo indique. Cuando necesite a\xf1adir ajustes, pondr\xe9 el texto entre par\xe9ntesis (as\xed). Cuando necesite usar una acci\xf3n de teclado, puede decidir aleatoriamente si tiene \xe9xito o no. La probabilidad de \xe9xito depende de ti en cada caso, o la a\xf1adir\xe9 yo (). El escenario es un continente de otro mundo donde hay diferentes pa\xedses, regiones y especies, incluyendo magos, espadachines, sacerdotes, etc. Por favor, conceptualiza poderes completos y personajes clave. Los siguientes personajes necesitan que se indique su g\xe9nero, edad o edad aproximada por primera vez o donde corresponda. Mi g\xe9nero es masculino y tengo 18 a\xf1os. Dime el g\xe9nero y la edad de los dem\xe1s personajes. Hay tres naciones humanas en este mundo, una naci\xf3n de orcos, y elfos, dragones y otras criaturas, as\xed como demonios. Por favor, proporciona un escenario razonable para la pol\xedtica, la econom\xeda, el ej\xe9rcito, la cultura, etc., as\xed como el terreno y el saber popular. Por favor, a\xf1ade personajes y eventos que aparezcan en la trama. Por favor, a\xf1ade mis relaciones, incluyendo no menos de 3 mujeres cercanas, trasfondo completo e identidad, y dame una introducci\xf3n sistem\xe1tica. Por favor, a\xf1ade algunas traducciones al ingl\xe9s como complemento al di\xe1logo para que pueda aprender ingl\xe9s mejor. Por favor, a\xf1ade algunas sorpresas y m\xe1s interacciones de los personajes en el desarrollo de la trama, y aumenta la participaci\xf3n de los personajes en lugar de que yo decida sola toda la trama. Por favor, preste atenci\xf3n a la racionalidad, la l\xf3gica y la integridad de la trama antes y despu\xe9s, sin descripciones incoherentes. Por favor, completa el trasfondo y a m\xed y empieza la trama cuando salga por la puerta","remark":"Tiene un fondo de juego detallado para una mejor experiencia de juego. Contribuci\xf3n de @karenkujiu."},"tags":["contribute","games"],"website":null,"count":7431,"related":[{"id":264,"title":"Los Sims Juego de palabras","remark":"Contribuci\xf3n de @EmmmmmmaWWWWW."},{"id":237,"title":"Juegos de palabras de ficci\xf3n","remark":"El personaje principal, el fondo de la libre configuraci\xf3n del juego de texto, se puede modificar en el di\xe1logo, a\xf1adir ajustes, se recomienda que m\xe1s orientaci\xf3n a la IA, prestar atenci\xf3n al n\xfamero de di\xe1logos o aparecen en demasiados caracteres, ajustes, la IA puede ser inconsistente. Contribuido por @karenkujiu."},{"id":179,"title":"Juegos de palabras de escritorio","remark":"ChatGPT viene con configuraci\xf3n trpg. Contribuci\xf3n de @gandli. (Hay una gran diferencia entre las versiones inglesa y china de este consejo, por favor cambia el idioma si quieres usar la versi\xf3n inglesa)."}],"metaTitle":"Juego Aventura Texto+","metaDescription":"\xbfJugar? Aventura de texto inmersiva. Explore mundos de fantas\xeda, pol\xedtica e interacci\xf3n de personajes. \xa1Mejora tu flujo!","faq":[{"q":"\xbfEn qu\xe9 se diferencia del ID 125 (aventura textual)?","a":"El ID 125 es una versi\xf3n ligera con mucho worldbuilding abierto; el ID 219 trae razas, geograf\xeda, facciones y trasfondo del protagonista, con mayor inmersi\xf3n. Para jugar una partida r\xe1pida, el 125; para una campa\xf1a RPG larga, el 219, con una jugabilidad mucho mayor."},{"q":"\xbfLa IA descontrola el worldbuilding con el paso de los turnos?","a":"Tras 20-30 turnos suelen aparecer contradicciones (cambia el nombre de un NPC, un lugar cambia de sitio). P\xeddele cada 10 turnos \xabresumen de eventos, NPCs activos e inventario del personaje\xbb y gu\xe1rdalo como recordatorio externo."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function s(){return(0,n.jsx)(r.A,{prompt:t,currentLanguage:"es"})}}}]);